-- ESTUDIAR · Fase E-2 (ALEMÁN) — A1+A2 (unidades 1-12), SOLO DATOS.
-- La tabla study_theory y las RPCs de mig 178 son course-agnósticas por
-- construcción (derivan el curso de la unidad) → en/pt/fr intactos.
-- Los ejemplos traen la clave canónica `text` (idioma meta). NO toca motor FSRS,
-- economía, gating, certificación ni los otros idiomas. Prueba FORMATIVA.


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 1, 'A1', 'Saludos y presentarte', 'Aprende a saludar y despedirte en alemán, a conjugar el verbo sein (ser/estar) y a decir tu nombre y de dónde vienes.', '[{"heading": "Saludar y despedirse", "body": "En alemán el saludo cambia según la hora y la confianza. «Hallo» sirve casi siempre. «Guten Morgen» es de mañana, «Guten Tag» de día y «Guten Abend» de tarde-noche. Para despedirte usas «Tschüss» con amigos y «Auf Wiedersehen» en situaciones formales.", "bullets": ["Hallo: informal, a cualquier hora del día.", "Guten Morgen / Guten Tag / Guten Abend según la hora.", "Tschüss es informal; Auf Wiedersehen es formal.", "Wie geht''s? = ¿Qué tal? Respuesta: Gut, danke."]}, {"heading": "El verbo sein (ser/estar)", "body": "«Sein» es el verbo más usado y es irregular: hay que memorizarlo. En alemán el pronombre sujeto nunca se omite, aunque en español sí. Además el verbo ocupa siempre la segunda posición de la frase.", "bullets": ["ich bin, du bist, er/sie/es ist.", "wir sind, ihr seid, sie sind.", "El pronombre es obligatorio: Ich bin Ana.", "En la frase principal el verbo va en segunda posición: Heute bin ich müde."]}, {"heading": "Presentarte: du o Sie", "body": "Para decir tu nombre usas «Ich heiße…» o «Mein Name ist…». Para tu origen, «Ich komme aus…». Con amigos y jóvenes tratas de «du»; con desconocidos y en el trabajo usas «Sie», que se escribe con mayúscula y toma la misma forma que el plural: Sie sind.", "bullets": ["Ich heiße Ana. / Mein Name ist Ana.", "Ich komme aus Peru. Ich wohne in Berlin.", "du bist (amigos) frente a Sie sind (formal).", "Wie heißen Sie? es formal; Wie heißt du? informal."]}]'::jsonb, '[{"de": "Hallo! Ich heiße Ana. Ich komme aus Peru.", "es": "¡Hola! Me llamo Ana. Vengo de Perú.", "text": "Hallo! Ich heiße Ana. Ich komme aus Peru.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a389e095-46e5-55aa-8c27-ce2c2e7d4ee0.mp3"}, {"de": "Guten Tag, Herr Müller! Wie geht es Ihnen?", "es": "¡Buenas tardes, señor Müller! ¿Cómo está usted?", "text": "Guten Tag, Herr Müller! Wie geht es Ihnen?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0bbc142a-51cb-50d2-99d5-605301fbdf39.mp3"}, {"de": "Das ist Markus. Er ist ein Freund von mir und er kommt aus Wien.", "es": "Este es Markus. Es un amigo mío y viene de Viena.", "text": "Das ist Markus. Er ist ein Freund von mir und er kommt aus Wien.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/099b47ad-620c-54c1-b8d2-25be5783ad5b.mp3"}, {"de": "Wir sind Studenten. Und ihr? Woher kommt ihr?", "es": "Somos estudiantes. ¿Y vosotros? ¿De dónde venís?", "text": "Wir sind Studenten. Und ihr? Woher kommt ihr?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0c6e5f63-e63f-5605-a66d-4ad172cb853d.mp3"}]'::jsonb, '[{"title": "No olvides el pronombre", "body": "En español dices «Soy Ana» sin pronombre, pero en alemán el sujeto es obligatorio: «Bin Ana» es incorrecto. Di siempre «Ich bin Ana» o «Ich heiße Ana»."}, {"title": "du no es lo mismo que Sie", "body": "«Du» es para amigos, familia y gente joven. Con un desconocido o en el trabajo se usa «Sie», que se escribe con mayúscula y lleva la misma forma verbal que el plural: «Sie sind Lehrer»."}, {"title": "El verbo va en segunda posición", "body": "Si empiezas la frase con otra palabra, el verbo no se mueve del segundo lugar: «Heute bin ich in Berlin», no «Heute ich bin in Berlin». En español el orden es más libre."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Te presentas a alguien por primera vez. ¿Qué frase es correcta?", "options": ["Ich heiße Ana.", "Heiße Ana.", "Ich heißen Ana."], "answer": "Ich heiße Ana.", "id": "u1q1"}, {"type": "cloze", "prompt": "Completa con la forma correcta del verbo sein (primera persona singular).", "text": "Ich ___ Studentin.", "answer": "bin", "accepted": ["bin"], "id": "u1q2"}, {"type": "multiple_choice", "prompt": "Completa con la forma de «sein» para «du»: «Du ___ sehr nett.»", "options": ["bist", "ist", "seid"], "answer": "bist", "id": "u1q3"}, {"type": "multiple_choice", "prompt": "Hablas con tu jefe (trato formal). ¿Cómo le preguntas su nombre?", "options": ["Wie heißen Sie?", "Wie heißt du?", "Wie heiße ich?"], "answer": "Wie heißen Sie?", "id": "u1q4"}, {"type": "cloze", "prompt": "Completa con la forma de sein para ''wir''.", "text": "Wir ___ aus Peru.", "answer": "sind", "accepted": ["sind"], "id": "u1q5"}]'::jsonb)
