values ('20000000-0000-0000-0000-000000000005', 2, 'A1', 'Números, edad y origen', 'Aprende a decir tu edad con el verbo sein, a contar hasta 100 con el orden alemán invertido y a decir de dónde vienes y dónde vives.', '[{"heading": "La edad va con SEIN, no con «tener»", "body": "En español «tienes» años; en alemán los «eres». Se usa el verbo sein: ich bin, du bist, er/sie ist. La fórmula completa es persona + sein + número + Jahre alt. En preguntas: Wie alt bist du?", "bullets": ["Ich bin 20 Jahre alt = Tengo 20 años.", "Du bist 15 Jahre alt. Sie ist 30 Jahre alt.", "Pregunta: Wie alt bist du?", "«Jahre alt» puede omitirse: Ich bin 20."]}, {"heading": "Los números y su orden invertido", "body": "Del 1 al 12 hay formas propias: eins, zwei, drei, vier, fünf, sechs, sieben, acht, neun, zehn, elf, zwölf. Del 13 al 19 se añade -zehn. Desde 21, la unidad va PRIMERO, unida con und: einundzwanzig.", "bullets": ["20 zwanzig, 30 dreißig, 40 vierzig, 100 hundert.", "21 = einundzwanzig, literalmente «uno-y-veinte».", "47 = siebenundvierzig; 99 = neunundneunzig.", "Ojo: 16 sechzehn y 17 siebzehn pierden letras; 1 pasa a ein-."]}, {"heading": "AUS para el origen, IN para dónde vives", "body": "Con kommen usa aus para el país o ciudad de donde vienes. Con wohnen usa in para el lugar donde vives ahora. Son dos preposiciones distintas y no se intercambian.", "bullets": ["Ich komme aus Peru. Ich wohne in Berlin.", "Preguntas: Woher kommst du? Wo wohnst du?", "Woher pide aus; wo pide in.", "Países con artículo: aus der Schweiz."]}]'::jsonb, '[{"de": "Ich bin fünfundzwanzig Jahre alt.", "es": "Tengo veinticinco años.", "text": "Ich bin fünfundzwanzig Jahre alt.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ba919bf0-2610-5a34-86f2-f4cb3ba12fc2.mp3"}, {"de": "Wie alt bist du? Ich bin einundzwanzig.", "es": "¿Cuántos años tienes? Tengo veintiuno.", "text": "Wie alt bist du? Ich bin einundzwanzig.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/879a4c01-cf5b-5017-89c1-5b8dba33760d.mp3"}, {"de": "Ich komme aus Peru, aber ich wohne in Berlin.", "es": "Vengo de Perú, pero vivo en Berlín.", "text": "Ich komme aus Peru, aber ich wohne in Berlin.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/896844a5-9c1b-5600-a335-29410281baab.mp3"}, {"de": "Meine Nummer ist siebenundvierzig.", "es": "Mi número es cuarenta y siete.", "text": "Meine Nummer ist siebenundvierzig.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7f62b0ff-f3ea-5be2-a2e4-0d68390a889b.mp3"}]'::jsonb, '[{"title": "«Ich habe 20 Jahre» no existe", "body": "Es un calco directo del español y suena mal en alemán. La edad se expresa con sein: Ich bin 20 Jahre alt. Recuérdalo así: en alemán no «tienes» años, los «eres»."}, {"title": "El número se oye al revés", "body": "En einundzwanzig oyes primero el 1 y luego el 20. Al escuchar teléfonos o precios, espera al final del número antes de anotarlo: sechsundachtzig es 86, no 68."}, {"title": "Los sustantivos van en mayúscula", "body": "Jahre, Berlin, Nummer y todos los sustantivos se escriben con mayúscula inicial en alemán, incluso dentro de la frase: Ich bin zwanzig Jahre alt."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «Tengo 20 años» en alemán?", "options": ["Ich bin 20 Jahre alt.", "Ich habe 20 Jahre.", "Ich habe 20 Jahre alt."], "answer": "Ich bin 20 Jahre alt.", "id": "u2q1"}, {"type": "multiple_choice", "prompt": "¿Qué número es «einundzwanzig»?", "options": ["21", "12", "121"], "answer": "21", "id": "u2q2"}, {"type": "cloze", "prompt": "Completa con el verbo sein: la edad nunca usa haben.", "text": "Ich ___ dreißig Jahre alt.", "answer": "bin", "accepted": ["bin"], "id": "u2q3"}, {"type": "cloze", "prompt": "Completa con la preposición del ORIGEN (con kommen).", "text": "Ich komme ___ Peru.", "answer": "aus", "accepted": ["aus"], "id": "u2q4"}, {"type": "cloze", "prompt": "Completa con la preposición del lugar donde VIVES (con wohnen).", "text": "Ich wohne ___ Berlin.", "answer": "in", "accepted": ["in"], "id": "u2q5"}]'::jsonb)
