insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 3, 'A1', 'La familia', 'Aprende a nombrar a tu familia en alemán con el artículo correcto (der, die, das) y a decir «mi» con mein o meine.', '[{"heading": "La familia viene con artículo", "body": "En alemán cada sustantivo tiene un género fijo: der (masculino), die (femenino), das (neutro). El género es parte de la palabra: aprende «der Vater», no «Vater» a secas. En plural, todos usan die.", "bullets": ["der Vater (padre), der Bruder (hermano), der Sohn (hijo)", "die Mutter (madre), die Schwester (hermana), die Tochter (hija)", "das Kind (hijo/a, criatura) es NEUTRO: das Kind", "Plural siempre con die: die Eltern, die Geschwister"]}, {"heading": "mein o meine: manda lo poseído", "body": "«Mi» no es invariable en alemán. Usa mein con masculinos y neutros, y meine con femeninos y con todo el plural. No importa si quien habla es hombre o mujer: decide el género de la persona poseída.", "bullets": ["mein Vater, mein Bruder, mein Kind (masculino y neutro)", "meine Mutter, meine Schwester (femenino)", "meine Eltern, meine Geschwister (plural, siempre meine)", "Como objeto, el masculino añade -en: «Ich habe meinen Bruder»."]}, {"heading": "Presentar a tu familia", "body": "Con estas palabras ya puedes hablar de los tuyos. Usa haben para decir a quién tienes y heißen para el nombre. El verbo va en segunda posición.", "bullets": ["Ich habe einen Bruder. (Tengo un hermano.)", "Meine Schwester heißt Ana.", "Das ist mein Vater. (Este es mi padre.)", "die Eltern solo existe en plural"]}]'::jsonb, '[{"de": "Das ist mein Vater. Er heißt Thomas.", "es": "Este es mi padre. Se llama Thomas.", "text": "Das ist mein Vater. Er heißt Thomas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c525dba4-ae4c-50e6-a404-bc64bddf8023.mp3"}, {"de": "Meine Schwester heißt Laura.", "es": "Mi hermana se llama Laura.", "text": "Meine Schwester heißt Laura.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b1065b33-8ddf-5ea0-9d4b-23dc7379d584.mp3"}, {"de": "Meine Eltern wohnen in Berlin.", "es": "Mis padres viven en Berlín.", "text": "Meine Eltern wohnen in Berlin.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a96bebf3-441c-56e5-ade4-03341c81a04e.mp3"}, {"de": "Das Kind spielt mit dem Hund.", "es": "El niño juega con el perro.", "text": "Das Kind spielt mit dem Hund.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/73d01a77-8efa-578b-82ed-8a070d4ba4dc.mp3"}]'::jsonb, '[{"title": "«mi» no es invariable: mein / meine", "body": "En español «mi» sirve para todo, y por eso se dice mal «meine Vater» o «mein Mutter». En alemán la -e depende de lo poseído: mein Vater, mein Kind, pero meine Mutter, meine Schwester, meine Eltern."}, {"title": "das Mädchen es neutro, no femenino", "body": "«Das Mädchen» (la chica) lleva das aunque hable de una mujer: la terminación -chen hace neutra la palabra. El género gramatical no es el sexo. Por eso se dice «mein Mädchen», no «meine Mädchen»."}, {"title": "die Eltern solo existe en plural", "body": "No hay «ein Eltern» para hablar de un solo progenitor: se dice der Vater o die Mutter. Igual pasa con die Geschwister (los hermanos en conjunto): para uno solo, der Bruder o die Schwester."}, {"title": "Los sustantivos van con mayúscula", "body": "En alemán todos los sustantivos se escriben con mayúscula inicial: der Vater, die Mutter, das Kind. Es una regla de escritura que conviene practicar, aunque el corrector de la app no distinga mayúsculas."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Completa: «___ Mutter kommt aus Spanien.» (Mi madre es de España.)", "options": ["Meine", "Mein", "Meinen"], "answer": "Meine", "id": "u3q1"}, {"type": "multiple_choice", "prompt": "«Das Mädchen» es neutro. ¿Cómo se dice «mi chica»?", "options": ["mein Mädchen", "meine Mädchen", "meinen Mädchen"], "answer": "mein Mädchen", "id": "u3q2"}, {"type": "cloze", "prompt": "Escribe el artículo correcto (der, die o das).", "text": "___ Vater arbeitet in Berlin.", "answer": "Der", "accepted": ["Der"], "id": "u3q3"}, {"type": "cloze", "prompt": "Escribe el artículo correcto (der, die o das). Recuerda: «Kind» es neutro.", "text": "___ Kind spielt im Garten.", "answer": "Das", "accepted": ["Das"], "id": "u3q4"}, {"type": "cloze", "prompt": "Escribe el artículo correcto (der, die o das) para «Schwester».", "text": "___ Schwester von Anna heißt Eva.", "answer": "Die", "accepted": ["Die"], "id": "u3q5"}]'::jsonb)
