insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 4, 'A1', 'Comida y en el café', 'Aprende a pedir con «Ich möchte…» y «Ich hätte gern…» y da tu primer paso en el Akkusativ: al pedir algo, solo el artículo masculino cambia (der→den, ein→einen).', '[{"heading": "Pedir con «Ich möchte…» y «Ich hätte gern…»", "body": "Para pedir en un café usa Ich möchte… (quisiera) o, aún más cortés, Ich hätte gern… Detrás va el producto y al final bitte. Möchte no cambia con ich ni con er/sie: ich möchte, er möchte.", "bullets": ["Ich möchte einen Tee, bitte. = Quisiera un té, por favor.", "Ich hätte gern eine Suppe. Suena todavía más cortés.", "El camarero pregunta: Was möchten Sie?", "También vale solo el producto: Einen Kaffee, bitte."]}, {"heading": "El Akkusativ: solo el masculino se disfraza", "body": "Lo que pides, tomas o comes es objeto directo y va en Akkusativ. Ahí el masculino cambia: der→den, ein→einen. El femenino (die, eine) y el neutro (das, ein) se quedan igual. El español no marca esto, por eso hay que memorizarlo.", "bullets": ["der Kaffee → Ich möchte den Kaffee / einen Kaffee.", "die Milch → Ich möchte die Milch / eine Milch.", "das Wasser → Ich möchte das Wasser / ein Wasser.", "Piden Akkusativ: möchten, nehmen, essen, trinken."]}, {"heading": "Sin género no hay caso", "body": "Si no sabes el género de la palabra, no puedes decidir entre einen y eine. Por eso aprende cada sustantivo junto a su artículo, como una sola pieza: der Kaffee, die Milch, das Wasser.", "bullets": ["Masculinos: der Kaffee, der Tee, der Saft, der Salat.", "Femeninos: die Milch, die Suppe, die Pizza, die Rechnung.", "Neutros: das Wasser, das Bier, das Brot, das Eis."]}]'::jsonb, '[{"de": "Ich möchte einen Kaffee, bitte.", "es": "Quisiera un café, por favor.", "text": "Ich möchte einen Kaffee, bitte.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/faf627ff-0cf3-59af-b106-4cf5991e9fb2.mp3"}, {"de": "Ich hätte gern eine Suppe und ein Wasser.", "es": "Quisiera una sopa y un agua.", "text": "Ich hätte gern eine Suppe und ein Wasser.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0e642017-c79c-52cf-a27f-8fdd02d6c935.mp3"}, {"de": "Nehmen Sie den Salat oder die Pizza?", "es": "¿Toma usted la ensalada o la pizza?", "text": "Nehmen Sie den Salat oder die Pizza?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e624d782-7995-50a7-9f22-8fa12fa13e17.mp3"}, {"de": "Wir möchten die Rechnung, bitte.", "es": "Queremos la cuenta, por favor.", "text": "Wir möchten die Rechnung, bitte.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/07165cba-11ae-520b-98d2-590db29e8d97.mp3"}]'::jsonb, '[{"title": "«Ich möchte ein Kaffee»: falta la -en", "body": "Kaffee es masculino (der Kaffee) y aquí es lo que pides, así que va en Akkusativ: Ich möchte einen Kaffee. Esa -en no es un adorno: es la marca del masculino como objeto directo."}, {"title": "«Un/una» del español no te dice el género", "body": "Decimos «un café» y «una sopa», pero el alemán reparte los géneros a su manera: der Kaffee es masculino y die Suppe femenino. Memoriza siempre la palabra con su artículo, no la traduzcas del español."}, {"title": "Los sustantivos van en mayúscula", "body": "Kaffee, Wasser, Suppe y Rechnung se escriben con mayúscula inicial siempre, también en medio de la frase: Ich möchte einen Kaffee und ein Wasser, bitte."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "«der Kaffee» es masculino. ¿Cómo se pide un café correctamente?", "options": ["Ich möchte einen Kaffee, bitte.", "Ich möchte ein Kaffee, bitte.", "Ich möchte der Kaffee, bitte."], "answer": "Ich möchte einen Kaffee, bitte.", "id": "u4q1"}, {"type": "multiple_choice", "prompt": "Al pedir algo (Akkusativ), ¿qué género cambia de artículo?", "options": ["el masculino", "el femenino", "el neutro"], "answer": "el masculino", "id": "u4q2"}, {"type": "cloze", "prompt": "Completa con el artículo DEFINIDO en Akkusativ. «der Salat» es masculino.", "text": "Ich nehme ___ Salat.", "answer": "den", "accepted": ["den"], "id": "u4q3"}, {"type": "multiple_choice", "prompt": "«der Tee» es masculino y aquí es objeto directo: «Ich möchte ___ Tee, bitte.»", "options": ["einen", "eine", "ein"], "answer": "einen", "id": "u4q4"}, {"type": "cloze", "prompt": "Completa con el artículo DEFINIDO. «die Milch» es femenino y no cambia en Akkusativ.", "text": "Ich möchte ___ Milch.", "answer": "die", "accepted": ["die"], "id": "u4q5"}]'::jsonb)
