insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 5, 'A1', 'El día y la hora', 'Aprende a preguntar y decir la hora en alemán, incluida la trampa de «halb vier» (3:30), y a nombrar los días de la semana con «am».', '[{"heading": "Preguntar y decir la hora", "body": "Para preguntar usas «Wie spät ist es?» y respondes con «Es ist…». Con la hora en punto añades «Uhr»: «Es ist drei Uhr». En horarios oficiales (trenes, citas) también se oye la forma con números: «drei Uhr dreißig» = 3:30.", "bullets": ["«Wie spät ist es?» = ¿Qué hora es?", "«Es ist zwei Uhr.» = Son las dos.", "Formal: «vierzehn Uhr dreißig» = 14:30."]}, {"heading": "halb, Viertel nach y Viertel vor", "body": "El alemán cuenta la media hora mirando HACIA ADELANTE: «halb vier» es media hora camino de las cuatro, o sea 3:30. Para los cuartos: «Viertel nach» es «y cuarto» y «Viertel vor» es «menos cuarto».", "bullets": ["«halb vier» = 3:30, no 4:30.", "«Viertel nach drei» = las tres y cuarto.", "«Viertel vor vier» = las cuatro menos cuarto.", "nach = después; vor = antes."]}, {"heading": "Los días de la semana", "body": "Los días son masculinos: der Montag, der Dienstag, der Mittwoch, der Donnerstag, der Freitag, der Samstag, der Sonntag. Para decir «el lunes» usas la preposición «am»: «am Montag».", "bullets": ["Todos los días son masculinos: der Montag.", "«am Montag» = el lunes.", "«Am Freitag arbeite ich nicht.»"]}]'::jsonb, '[{"de": "Wie spät ist es? Es ist halb vier.", "es": "¿Qué hora es? Son las tres y media.", "text": "Wie spät ist es? Es ist halb vier.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/200adac2-4e6b-5ed8-872a-250132d98e0f.mp3"}, {"de": "Der Kurs beginnt um Viertel nach neun.", "es": "El curso empieza a las nueve y cuarto.", "text": "Der Kurs beginnt um Viertel nach neun.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/866d4754-3edd-5978-967a-b8dfd5896ac7.mp3"}, {"de": "Wir essen um Viertel vor eins.", "es": "Comemos a la una menos cuarto.", "text": "Wir essen um Viertel vor eins.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5bde1a26-9cf0-5e19-9fd0-8de2bf189d7d.mp3"}, {"de": "Am Montag habe ich einen Termin.", "es": "El lunes tengo una cita.", "text": "Am Montag habe ich einen Termin.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/150128b0-0d7d-554a-ac26-1deb97616364.mp3"}]'::jsonb, '[{"title": "«halb vier» no es las cuatro y media", "body": "En español dices «cuatro y media» mirando la hora que pasó; el alemán mira la que viene. «halb vier» = 3:30 y «halb fünf» = 4:30. Si quedas «um halb sechs», llegas a las 5:30."}, {"title": "«nach» y «vor» se confunden", "body": "«nach» significa después (y cuarto) y «vor» significa antes (menos cuarto). «Viertel nach acht» son las 8:15; «Viertel vor acht» son las 7:45. Una palabra distinta cambia media hora de tu día."}, {"title": "Los días llevan mayúscula y «am»", "body": "Todos los sustantivos alemanes se escriben con mayúscula, también los días: Montag, Dienstag. Y para decir «el lunes» no se usa el artículo suelto sino «am Montag» (am = an dem)."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Tu amigo dice «Wir treffen uns um halb vier». ¿A qué hora se ven?", "options": ["A las 3:30", "A las 4:30", "A las 4:15"], "answer": "A las 3:30", "id": "u5q1"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «las siete y cuarto» en alemán?", "options": ["Viertel nach sieben", "Viertel vor sieben", "halb sieben"], "answer": "Viertel nach sieben", "id": "u5q2"}, {"type": "cloze", "prompt": "Completa con «nach» o «vor»: son las 9:45, es decir, un cuarto ANTES de las diez.", "text": "Es ist Viertel ___ zehn.", "answer": "vor", "accepted": ["vor"], "id": "u5q3"}, {"type": "cloze", "prompt": "Completa con la preposición que se usa con los días de la semana: «El viernes voy al cine».", "text": "___ Freitag gehe ich ins Kino.", "answer": "Am", "accepted": ["am"], "id": "u5q4"}, {"type": "multiple_choice", "prompt": "¿Cuál es el artículo correcto de «Montag»?", "options": ["der", "die", "das"], "answer": "der", "id": "u5q5"}]'::jsonb)
