insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 6, 'A1', 'La ciudad y direcciones', 'Aprende a preguntar dónde está un lugar («Wo ist…?»), a decir que algo existe con «Es gibt» + acusativo, y a dar direcciones básicas en la ciudad.', '[{"heading": "«Wo ist…?»: preguntar por un lugar concreto", "body": "Con «Wo ist…?» preguntas por la ubicación de un lugar concreto que esperas encontrar. El sustantivo va con su artículo normal: der, die, das. Puedes responder con «Er/Sie/Es ist…» o de forma corta: «Dort» (allí).", "bullets": ["Wo ist der Bahnhof? – ¿Dónde está la estación?", "Cada lugar con su artículo: der Bahnhof, die Straße, das Rathaus.", "Respuesta corta: «Dort» o «Da vorne» (allí delante)."]}, {"heading": "«Es gibt» + acusativo: decir que algo existe", "body": "«Es gibt» significa «hay» y siempre lleva acusativo. Por eso el masculino cambia: ein → einen. El femenino y el neutro no cambian: eine, ein. El sujeto es siempre «es» y el verbo en presente, siempre «gibt».", "bullets": ["Masculino: Es gibt einen Park. (der Park → einen Park)", "Femenino: Es gibt eine Kirche. Neutro: Es gibt ein Museum.", "Pregunta: Gibt es hier einen Supermarkt?"]}, {"heading": "Direcciones: links, rechts, geradeaus", "body": "Para indicar el camino se usa el imperativo formal «Gehen Sie…» y después la dirección: links (izquierda), rechts (derecha), geradeaus (todo recto). Con «die erste Straße links» dices «la primera calle a la izquierda».", "bullets": ["Gehen Sie geradeaus, dann links. – Siga recto, luego a la izquierda.", "Nehmen Sie die erste Straße rechts. – Tome la primera calle a la derecha.", "Cerca o lejos: Es ist hier in der Nähe."]}]'::jsonb, '[{"de": "Wo ist der Bahnhof, bitte?", "es": "¿Dónde está la estación, por favor?", "text": "Wo ist der Bahnhof, bitte?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1a99cae1-9954-5230-b3ad-f0a4edde7246.mp3"}, {"de": "In meiner Stadt gibt es einen Park und eine Kirche.", "es": "En mi ciudad hay un parque y una iglesia.", "text": "In meiner Stadt gibt es einen Park und eine Kirche.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f512ea78-eb42-5d92-8ce9-c4ad057e1b21.mp3"}, {"de": "Gehen Sie geradeaus und dann links.", "es": "Siga todo recto y luego a la izquierda.", "text": "Gehen Sie geradeaus und dann links.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/146530fe-47a5-5435-9596-ca0e83b13040.mp3"}, {"de": "Das Rathaus ist rechts, neben der Post.", "es": "El ayuntamiento está a la derecha, al lado de correos.", "text": "Das Rathaus ist rechts, neben der Post.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6b9f44fb-e73c-5f3f-bb72-2bd8042941fa.mp3"}]'::jsonb, '[{"title": "«Wo ist…?» no es lo mismo que «Es gibt…»", "body": "«Wo ist der Park?» pregunta por uno concreto; «Gibt es hier einen Park?» pregunta si existe. También puedes combinarlas: «Wo gibt es hier einen Park?» ✅. Pero «gibt es» sigue pidiendo acusativo: «Wo gibt es der Park?» ❌."}, {"title": "«Es gibt» pide acusativo: einen, no ein", "body": "En masculino el artículo cambia: «Es gibt ein Park» ❌ → «Es gibt einen Park» ✅. Femenino y neutro se quedan igual: eine Kirche, ein Museum. Es el error número uno del hispanohablante con «hay»."}, {"title": "Cada lugar se aprende con su artículo (y su mayúscula)", "body": "En alemán los sustantivos se escriben con mayúscula: Bahnhof, Straße, Rathaus. Y el artículo forma parte de la palabra: der Bahnhof, die Straße, das Rathaus. Memoriza siempre artículo + sustantivo juntos."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo preguntas dónde está la estación?", "options": ["Wo ist der Bahnhof?", "Was ist der Bahnhof?", "Es gibt den Bahnhof."], "answer": "Wo ist der Bahnhof?", "id": "u6q1"}, {"type": "multiple_choice", "prompt": "¿Cuál frase usa «es gibt» correctamente (hay un parque aquí)?", "options": ["Hier gibt es einen Park.", "Hier gibt es ein Park.", "Hier gibt einen Park."], "answer": "Hier gibt es einen Park.", "id": "u6q2"}, {"type": "multiple_choice", "prompt": "«der Supermarkt» es masculino y «es gibt» pide Akkusativ: «Es gibt ___ Supermarkt in der Stadt.»", "options": ["einen", "eine", "ein"], "answer": "einen", "id": "u6q3"}, {"type": "cloze", "prompt": "Completa con la palabra alemana para «todo recto».", "text": "Gehen Sie ___ und dann rechts.", "answer": "geradeaus", "accepted": ["geradeaus"], "id": "u6q4"}, {"type": "cloze", "prompt": "Completa con la palabra para preguntar «dónde».", "text": "___ ist das Rathaus, bitte?", "answer": "Wo", "accepted": ["wo"], "id": "u6q5"}]'::jsonb)
