insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 7, 'A2', 'El pasado: lo que hice', 'Aprende a contar lo que hiciste con el Perfekt: «haben» conjugado en segunda posición y el Partizip II al final de la frase.', '[{"heading": "haben en 2ª posición, participio al final", "body": "En el Perfekt, «haben» ocupa la 2ª posición, como cualquier verbo conjugado. El Partizip II se va al FINAL, aunque queden varias palabras en medio. Los dos forman un marco que encierra toda la frase: «Ich habe gestern einen Film gesehen».", "bullets": ["«haben»: habe, hast, hat, haben, habt, haben.", "El Partizip II cierra la frase, siempre.", "En medio van tiempo, lugar y objeto.", "En preguntas de sí/no «haben» va primero; con Was/Wann, segundo."]}, {"heading": "Cómo se forma el Partizip II", "body": "Los regulares hacen ge- + raíz + -t: machen → gemacht, kaufen → gekauft. Los irregulares frecuentes hacen ge- + raíz (a veces cambiada) + -en: sehen → gesehen, essen → gegessen, trinken → getrunken, lesen → gelesen, schreiben → geschrieben.", "bullets": ["Regulares: gemacht, gekauft, gelernt, gespielt.", "Irregulares: gesehen, gegessen, getrunken, gelesen, geschrieben.", "Verbos en -ieren nunca llevan ge-: studiert, telefoniert."]}, {"heading": "Cuándo se usa", "body": "El Perfekt alemán cubre las dos formas del español: «hice» y «he hecho». Es el pasado normal de la conversación diaria. No tienes que elegir entre una y otra: «Ich habe gearbeitet» sirve para las dos.", "bullets": ["«Ich habe gearbeitet» = trabajé y he trabajado.", "Es el pasado de la lengua hablada.", "Con «gestern» o «letzte Woche» también se usa Perfekt."]}]'::jsonb, '[{"de": "Ich habe gestern einen Film gesehen.", "es": "Ayer vi una película.", "text": "Ich habe gestern einen Film gesehen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ecb802c9-ede5-5c15-ab54-8713fba5496b.mp3"}, {"de": "Wir haben im Restaurant Pizza gegessen.", "es": "Comimos pizza en el restaurante.", "text": "Wir haben im Restaurant Pizza gegessen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/16aee97d-c58d-5fa4-b73f-655033fe6edf.mp3"}, {"de": "Hast du den Brief schon geschrieben?", "es": "¿Ya escribiste la carta?", "text": "Hast du den Brief schon geschrieben?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7b6a6d65-bc79-53c4-bba2-fe1d161c1a1f.mp3"}, {"de": "Sie hat in Berlin Medizin studiert.", "es": "Ella estudió Medicina en Berlín.", "text": "Sie hat in Berlin Medizin studiert.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a816622a-fa85-5112-b9bb-f1b852a988cb.mp3"}]'::jsonb, '[{"title": "No pegues el participio al auxiliar", "body": "En español decimos «he visto una película» con las dos partes juntas. En alemán no: «Ich habe gesehen einen Film» es incorrecto. El participio salta hasta el final: «Ich habe einen Film gesehen»."}, {"title": "Los verbos en -ieren no llevan ge-", "body": "studieren → studiert, telefonieren → telefoniert, fotografieren → fotografiert. Decir «gestudiert» es un error muy frecuente. Solo se añade la -t final."}, {"title": "No todos los verbos usan haben", "body": "Algunos verbos, sobre todo de movimiento y cambio (gehen, fahren, kommen), forman el Perfekt con «sein»: «Ich bin nach Hause gegangen». Eso se trabaja aparte; aquí practicamos solo los de «haben»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la frase correcta en Perfekt.", "options": ["Ich habe gestern einen Film gesehen.", "Ich habe gesehen gestern einen Film.", "Ich gesehen habe gestern einen Film."], "answer": "Ich habe gestern einen Film gesehen.", "id": "u7q1"}, {"type": "multiple_choice", "prompt": "Elige la frase correcta con el verbo «studieren».", "options": ["Sie hat in Berlin Medizin studiert.", "Sie hat in Berlin Medizin gestudiert.", "Sie hat studiert in Berlin Medizin."], "answer": "Sie hat in Berlin Medizin studiert.", "id": "u7q2"}, {"type": "cloze", "prompt": "Completa con el Partizip II de «essen».", "text": "Wir haben gestern Pizza ___.", "answer": "gegessen", "accepted": ["gegessen"], "id": "u7q3"}, {"type": "cloze", "prompt": "Completa con el PRESENTE de «haben» para «er» (Perfekt).", "text": "Er ___ einen Brief geschrieben.", "answer": "hat", "accepted": ["hat"], "id": "u7q4"}, {"type": "cloze", "prompt": "Completa con el Partizip II de «machen».", "text": "Was hast du am Wochenende ___?", "answer": "gemacht", "accepted": ["gemacht"], "id": "u7q5"}]'::jsonb)
