insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 8, 'A2', 'Planes y futuro', 'En alemán el futuro se dice casi siempre con el PRESENTE más una marca de tiempo. La clave es que el verbo conjugado ocupa siempre el segundo lugar de la frase.', '[{"heading": "El presente ya es futuro", "body": "Para hablar de planes, el alemán usa el presente normal y añade una marca de tiempo: morgen, heute Abend, nächste Woche, am Montag. No existe un «ir a + infinitivo» como en español: «voy a viajar» se dice simplemente «ich fahre».", "bullets": ["Presente + marca de tiempo = futuro natural.", "morgen, heute Abend, nächste Woche, am Montag.", "«Ich fahre morgen» significa «viajo/voy a viajar mañana»."]}, {"heading": "El verbo va SIEMPRE en segundo lugar", "body": "Si empiezas la frase con la marca de tiempo, el verbo no se mueve: sigue siendo el segundo elemento y el sujeto pasa detrás. Por eso decimos «Morgen fahre ich nach Berlin» y nunca «Morgen ich fahre».", "bullets": ["Ich fahre morgen nach Berlin. (sujeto primero)", "Morgen fahre ich nach Berlin. (tiempo primero)", "El sujeto salta detrás del verbo: fahre ich.", "Cuenta elementos, no palabras: «Nächste Woche» es uno."]}, {"heading": "werden + infinitivo: predicción o promesa", "body": "También existe «werden + infinitivo», con el infinitivo al final. No es obligatorio ni más correcto: se usa sobre todo para predicciones o promesas. En el día a día, los planes concretos van en presente.", "bullets": ["Es wird morgen regnen. (predicción)", "Ich werde dir helfen. (promesa)", "werden conjugado en 2.º lugar, infinitivo al final."]}]'::jsonb, '[{"de": "Morgen fahre ich nach Berlin.", "es": "Mañana voy a Berlín.", "text": "Morgen fahre ich nach Berlin.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5f8d7c9d-ccb5-531b-94a7-2968fe3f437e.mp3"}, {"de": "Nächste Woche besuchen wir meine Eltern.", "es": "La semana que viene visitamos a mis padres.", "text": "Nächste Woche besuchen wir meine Eltern.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4d8bb192-7d7d-556d-96cc-d7ac07299a3c.mp3"}, {"de": "Heute Abend koche ich Suppe.", "es": "Esta noche cocino sopa.", "text": "Heute Abend koche ich Suppe.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3c9bf49d-7635-507b-870c-6e8b3809ad1d.mp3"}, {"de": "Es wird morgen regnen.", "es": "Mañana va a llover.", "text": "Es wird morgen regnen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c3fb8215-81c0-50af-ab7c-3becf28b83a2.mp3"}]'::jsonb, '[{"title": "«Morgen ich fahre» ✗", "body": "Es el calco del español y el error número uno. Al empezar con la marca de tiempo, el verbo conjugado se queda en segundo lugar y el sujeto pasa detrás: «Morgen fahre ich nach Berlin»."}, {"title": "Buscar un «ir a + infinitivo»", "body": "«Voy a estudiar» no se traduce con «gehen». El alemán usa el presente: «Ich lerne heute Abend». Usar «gehen zu» suena a movimiento físico, no a plan."}, {"title": "Los sustantivos van con mayúscula", "body": "Berlin, Woche, Abend, Suppe se escriben siempre con mayúscula, también dentro de la frase. La prueba no distingue mayúsculas, pero al escribir a mano o en un examen real sí cuenta."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Empieza la frase con «Morgen». ¿Cuál es el orden correcto?", "options": ["Morgen fahre ich nach Berlin.", "Morgen ich fahre nach Berlin.", "Morgen nach Berlin ich fahre."], "answer": "Morgen fahre ich nach Berlin.", "id": "u8q1"}, {"type": "multiple_choice", "prompt": "Empieza la frase con «Nächste Woche». ¿Cuál es correcta?", "options": ["Nächste Woche besuchen wir meine Eltern.", "Nächste Woche wir besuchen meine Eltern.", "Nächste Woche meine Eltern besuchen wir."], "answer": "Nächste Woche besuchen wir meine Eltern.", "id": "u8q2"}, {"type": "multiple_choice", "prompt": "Quieres decir «Esta noche cocino sopa» (un plan concreto, en presente). ¿Cuál eliges?", "options": ["Heute Abend koche ich Suppe.", "Heute Abend ich koche Suppe.", "Heute Abend Suppe koche ich."], "answer": "Heute Abend koche ich Suppe.", "id": "u8q3"}, {"type": "multiple_choice", "prompt": "Empieza la frase con «Am Montag» y usa «arbeiten». ¿Cuál es correcta?", "options": ["Am Montag arbeite ich in Hamburg.", "Am Montag ich arbeite in Hamburg.", "Am Montag arbeiten ich in Hamburg."], "answer": "Am Montag arbeite ich in Hamburg.", "id": "u8q4"}, {"type": "cloze", "prompt": "Predicción con «werden». Escribe la forma de «werden» para «es».", "text": "Es ___ morgen regnen.", "answer": "wird", "accepted": ["wird"], "id": "u8q5"}]'::jsonb)
