insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 9, 'A2', 'De viaje', 'Aprende a contar tus viajes en pasado: el Perfekt con sein para verbos de movimiento y cambio de estado, más el vocabulario básico del tren y el aeropuerto.', '[{"heading": "Perfekt con sein: te moviste o cambiaste de estado", "body": "En pasado, la mayoría de verbos usa haben. Pero los verbos que expresan un cambio de LUGAR (gehen, fahren, fliegen, kommen) o un cambio de ESTADO (aufstehen, einschlafen) usan sein. Pregúntate: ¿me moví de sitio? ¿pasé de un estado a otro? Si sí, va sein.", "bullets": ["Ich bin nach Berlin gefahren. (cambio de lugar)", "Er ist um sechs aufgestanden. (cambio de estado)", "Wir sind mit dem Flugzeug geflogen.", "Sie ist gestern gekommen."]}, {"heading": "bleiben: la excepción que hay que memorizar", "body": "bleiben significa quedarse: no hay ningún movimiento. Aun así va con sein: Ich bin zu Hause geblieben. Es la excepción clásica y entra siempre en los exámenes. Memorízala junto a sein mismo: Ich bin dort gewesen (he estado allí).", "bullets": ["Ich bin im Hotel geblieben.", "Wir sind eine Woche in Wien geblieben.", "bleiben y sein van con sein, sin movimiento."]}, {"heading": "El participio al final y el vocabulario del viaje", "body": "El auxiliar (bin, ist, sind) ocupa el segundo lugar y el participio se va al FINAL de la frase, con todo lo demás en medio. Aprende cada palabra de viaje con su artículo: son parte de la palabra.", "bullets": ["Ich bin gestern mit dem Zug gefahren.", "der Zug, das Flugzeug, die Fahrkarte", "der Bahnhof, der Flughafen, der Koffer", "Auxiliar 2º en la enunciativa (1º en preguntas sí/no); participio al final."]}]'::jsonb, '[{"de": "Ich bin mit dem Zug nach München gefahren.", "es": "Fui a Múnich en tren.", "text": "Ich bin mit dem Zug nach München gefahren.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/257b11e4-8d93-527b-99ec-8a38430b7248.mp3"}, {"de": "Wir sind am Montag nach Spanien geflogen.", "es": "El lunes volamos a España.", "text": "Wir sind am Montag nach Spanien geflogen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e0c43b39-479d-5a94-b6e0-f677dab0a535.mp3"}, {"de": "Am Sonntag bin ich zu Hause geblieben.", "es": "El domingo me quedé en casa.", "text": "Am Sonntag bin ich zu Hause geblieben.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1c935668-514b-56c2-9756-c9266871bfeb.mp3"}, {"de": "Hast du die Fahrkarte am Bahnhof gekauft?", "es": "¿Compraste el billete en la estación?", "text": "Hast du die Fahrkarte am Bahnhof gekauft?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/bc0350d5-441c-541a-93f7-07919ac2827e.mp3"}]'::jsonb, '[{"title": "«Ich habe gefahren» ✗", "body": "En español todo el pasado se forma con haber, así que copiamos haben para todo. En alemán, fahren, gehen, fliegen y kommen piden sein: Ich BIN gefahren, du BIST gegangen, er IST geflogen. Es el error número uno del hispanohablante."}, {"title": "bleiben no se mueve, pero va con sein", "body": "El truco del movimiento falla aquí: quedarse es lo contrario de moverse. Aun así: Ich bin geblieben (nunca «Ich habe geblieben»). Apréndela de memoria junto con sein: Ich bin gewesen."}, {"title": "Un mismo verbo, dos auxiliares", "body": "Algunos verbos cambian de auxiliar según el sentido. Sin objeto, fahren indica movimiento propio: Ich bin nach Köln gefahren. Con objeto directo (conducir algo) usa haben: Ich habe das Auto gefahren. Si hay objeto, piensa en haben."}]'::jsonb, '[{"type": "cloze", "prompt": "Completa con el auxiliar correcto. Movimiento hacia otro lugar.", "text": "Ich ___ gestern mit dem Zug nach Hamburg gefahren.", "answer": "bin", "accepted": ["bin"], "id": "u9q1"}, {"type": "cloze", "prompt": "Completa con el auxiliar correcto. Recuerda la excepción.", "text": "Am Wochenende ___ wir zu Hause geblieben.", "answer": "sind", "accepted": ["sind"], "id": "u9q2"}, {"type": "multiple_choice", "prompt": "¿Cuál es el participio correcto de «fliegen»?", "options": ["geflogen", "gefliegt", "gefliegen"], "answer": "geflogen", "id": "u9q3"}, {"type": "multiple_choice", "prompt": "Elige la frase con el orden correcto (participio al final).", "options": ["Er ist um sieben Uhr aufgestanden.", "Er ist aufgestanden um sieben Uhr.", "Er aufgestanden ist um sieben Uhr."], "answer": "Er ist um sieben Uhr aufgestanden.", "id": "u9q4"}, {"type": "multiple_choice", "prompt": "¿Qué artículo lleva «Fahrkarte» (billete)?", "options": ["die", "der", "das"], "answer": "die", "id": "u9q5"}]'::jsonb)
