insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 10, 'A2', 'Comer fuera y comprar', 'Aprende a comparar precios, tamaños y sabores en el restaurante y en la tienda: comparativo con -er + als, el Umlaut, los irregulares (besser, mehr, lieber) y so … wie para la igualdad.', '[{"heading": "Comparar cosas distintas: -er + als", "body": "Para decir que algo es MÁS que otra cosa, añade -er al adjetivo y une las dos partes con «als». En el restaurante y en la tienda lo usas todo el tiempo: comparas precios, raciones y calidad. «als» equivale a nuestro «que», no a «como».", "bullets": ["billig → billiger: Der Salat ist billiger als die Suppe.", "klein → kleiner: Diese Portion ist kleiner als die andere.", "El adjetivo tras «ist» no lleva terminación extra.", "En la conversación informal se oye «wie», pero el estándar es «als»."]}, {"heading": "Muchos adjetivos cortos ganan Umlaut", "body": "Varios adjetivos de una sílaba con a, o, u cambian la vocal al comparar. No es opcional: forma parte de la palabra. Y ojo: en alemán nunca se dice «mehr billig»; el comparativo se hace SIEMPRE con -er, aunque en español digamos «más barato».", "bullets": ["alt → älter, jung → jünger, lang → länger.", "groß → größer, warm → wärmer, kurz → kürzer.", "Sin Umlaut: schnell → schneller, klar → klarer.", "«mehr billig» ✗ — se dice «billiger» ✓."]}, {"heading": "Irregulares y la igualdad con so … wie", "body": "Tres adjetivos muy usados al comer y comprar son irregulares y hay que memorizarlos. Y cuando dos cosas son IGUALES, no usas «als»: usas la pareja «so … wie», que sí equivale a nuestro «tan … como».", "bullets": ["gut → besser → am besten; viel → mehr; gern → lieber.", "Ich esse lieber Fisch als Fleisch.", "Igualdad: Der Kaffee ist so teuer wie der Tee.", "En la mesa: die Speisekarte, die Rechnung, der Preis."]}]'::jsonb, '[{"de": "Dieses Restaurant ist billiger als das andere.", "es": "Este restaurante es más barato que el otro.", "text": "Dieses Restaurant ist billiger als das andere.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c6c4e7a8-6abd-5525-a610-32ba934b73d4.mp3"}, {"de": "Der Supermarkt ist größer als der Markt, aber der Markt ist besser.", "es": "El supermercado es más grande que el mercado, pero el mercado es mejor.", "text": "Der Supermarkt ist größer als der Markt, aber der Markt ist besser.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0fc06239-27bf-574f-a2ee-661ef58c7fe6.mp3"}, {"de": "Ich trinke lieber Wasser als Wein.", "es": "Prefiero beber agua a vino.", "text": "Ich trinke lieber Wasser als Wein.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6351d7ae-6941-5bbb-a1d0-539de06ede85.mp3"}, {"de": "Die Rechnung, bitte! Der Fisch war teurer als das Hähnchen.", "es": "¡La cuenta, por favor! El pescado era más caro que el pollo.", "text": "Die Rechnung, bitte! Der Fisch war teurer als das Hähnchen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/cfa42dc4-f91b-5fb3-96ee-35340b641958.mp3"}]'::jsonb, '[{"title": "«billiger wie» en vez de «billiger als»", "body": "El español dice «más barato QUE», y muchos calcan «wie» porque suena a «como». En la comparación de desigualdad el alemán estándar exige «als»: «Der Wein ist teurer als das Bier». «wie» solo aparece en la igualdad: «so teuer wie». En el habla coloquial se oye «wie», pero no lo escribas ni lo digas en un examen."}, {"title": "Olvidar el Umlaut del comparativo", "body": "«Diese Portion ist grosser» ✗. Muchos monosílabos cambian la vocal: groß → größer, alt → älter, jung → jünger, lang → länger, warm → wärmer. No todos lo hacen (schnell → schneller), así que aprende cada adjetivo con su comparativo. Si escribes desde un teclado sin Umlaut, «groesser» es la forma sustituta aceptada."}, {"title": "Formar el comparativo con «mehr»", "body": "«Das ist mehr billig» ✗. El alemán no usa «mehr» delante del adjetivo como el español usa «más»: el comparativo se marca con -er (billiger, teurer, kleiner). «mehr» es solo el comparativo de «viel»: «Ich möchte mehr Salat» = quiero más ensalada. Recuerda también: la mayúscula del sustantivo (Salat, Suppe) se mantiene siempre."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "En la tienda comparas dos precios. ¿Cuál es la forma correcta de «más barato»?", "options": ["billiger", "mehr billig", "billigst"], "answer": "billiger", "id": "u10q1"}, {"type": "multiple_choice", "prompt": "Elige el comparativo correcto de «groß» (la porción es más grande).", "options": ["größer", "mehr groß", "am größten"], "answer": "größer", "id": "u10q2"}, {"type": "multiple_choice", "prompt": "«gut» es irregular. ¿Cuál es su comparativo?", "options": ["besser", "guter", "mehr gut"], "answer": "besser", "id": "u10q3"}, {"type": "cloze", "prompt": "Completa con la palabra que une una comparación de DESIGUALDAD (más ... que).", "text": "Der Fisch ist teurer ___ das Hähnchen.", "answer": "als", "accepted": ["als"], "id": "u10q4"}, {"type": "cloze", "prompt": "Completa: aquí las dos cosas cuestan lo MISMO (tan caro como). Ya está puesto «so».", "text": "Der Kaffee ist so teuer ___ der Tee.", "answer": "wie", "accepted": ["wie"], "id": "u10q5"}]'::jsonb)
