insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 11, 'A2', 'Personas y descripciones', 'Para describir cómo era alguien o qué tenía, el alemán prefiere el Präteritum de sein y haben: war y hatte. Y practicas los adjetivos que describen a una persona.', '[{"heading": "«war»: el pasado de sein para describir", "body": "En el día a día el pasado se cuenta en Perfekt, pero «sein» es la gran excepción: para describir cómo era algo o alguien se usa «war». «Ich bin gewesen» existe y no es un error, pero se prefiere «war» en el norte y por escrito; en el sur se oye «bin gewesen».", "bullets": ["ich war, du warst, er/sie war, wir waren, ihr wart, sie waren", "«er war» no lleva -t: nunca «er warte»", "Als Kind war ich klein. = De niño yo era pequeño."]}, {"heading": "«hatte»: el pasado de haben", "body": "«haben» funciona igual: para decir qué tenías, usa «hatte», no «ich habe gehabt». Es la forma normal para describir posesiones, edad, tiempo o sensaciones en el pasado.", "bullets": ["ich hatte, du hattest, er/sie hatte, wir hatten", "Sie hatte einen Hund. = Ella tenía un perro.", "Wir hatten keine Zeit. = No teníamos tiempo."]}, {"heading": "Adjetivos para describir personas", "body": "Después del verbo «sein» el adjetivo se queda tal cual, sin terminación, sea quien sea la persona: hombre, mujer o plural. Cuando el adjetivo va delante del sustantivo sí cambia, pero eso esas terminaciones las trabajarás más adelante.", "bullets": ["groß, klein, nett, freundlich, ruhig", "Er ist nett. / Sie ist nett. / Sie sind nett.", "Nunca «Sie ist nette» después del verbo"]}]'::jsonb, '[{"de": "Als Kind war ich sehr schüchtern.", "es": "De niño yo era muy tímido.", "text": "Als Kind war ich sehr schüchtern.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/de20a767-1ab1-5596-86aa-ee022465be46.mp3"}, {"de": "Meine Lehrerin war klein und sehr freundlich.", "es": "Mi profesora era baja y muy amable.", "text": "Meine Lehrerin war klein und sehr freundlich.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f1319de5-de0a-550f-9502-19a7c8a173e9.mp3"}, {"de": "Wir hatten damals einen großen Garten.", "es": "En aquel entonces teníamos un jardín grande.", "text": "Wir hatten damals einen großen Garten.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c0a774a3-55ce-51df-8925-d536ea78c0e6.mp3"}, {"de": "Mein Bruder ist ruhig, aber meine Schwester ist laut.", "es": "Mi hermano es tranquilo, pero mi hermana es ruidosa.", "text": "Mein Bruder ist ruhig, aber meine Schwester ist laut.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6b0da1a3-7a9c-54d9-b720-02e1a8aa923f.mp3"}]'::jsonb, '[{"title": "«Ich bin gewesen» no está mal, pero casi nadie lo dice", "body": "Con sein y haben el alemán prefiere el Präteritum en la conversación: «Ich war müde», «Ich hatte Hunger». «Ich bin müde gewesen» se entiende y es correcto, pero suena pesado. Usa war y hatte."}, {"title": "«er war» sin -t", "body": "En presente decimos «er hat», «er macht», y la tentación es escribir «er warte». No existe como pasado de «sein» («warte» es de «warten» = esperar): la tercera persona de war es igual que la primera. Ich war = er war. Lo mismo con hatte: ich hatte = er hatte."}, {"title": "Los adjetivos, en alemán, van en minúscula", "body": "Los sustantivos alemanes se escriben con mayúscula (der Hund, die Zeit), pero los adjetivos no: «Er ist nett», «ein großer Garten». Escribir «Er ist Nett» es un error de ortografía muy típico del principiante."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «De niño yo era muy tímido»?", "options": ["Als Kind war ich sehr schüchtern.", "Als Kind bin ich sehr schüchtern.", "Als Kind hatte ich sehr schüchtern."], "answer": "Als Kind war ich sehr schüchtern.", "id": "u11q1"}, {"type": "multiple_choice", "prompt": "Elige la forma correcta del pasado de «haben» para «wir» (nosotros).", "options": ["Wir hatten keine Zeit.", "Wir waren keine Zeit.", "Wir hattest keine Zeit."], "answer": "Wir hatten keine Zeit.", "id": "u11q2"}, {"type": "multiple_choice", "prompt": "Präteritum de «sein» para «meine Lehrerin» (3ª persona): «Meine Lehrerin ___ sehr freundlich.»", "options": ["war", "wart", "warte"], "answer": "war", "id": "u11q3"}, {"type": "cloze", "prompt": "Completa con el Präteritum de «sein» para «du».", "text": "Du ___ gestern sehr ruhig.", "answer": "warst", "accepted": ["warst"], "id": "u11q4"}, {"type": "multiple_choice", "prompt": "Después del verbo «sein», ¿cuál es la forma correcta del adjetivo?", "options": ["Sie ist nett.", "Sie ist nette.", "Sie ist netten."], "answer": "Sie ist nett.", "id": "u11q5"}]'::jsonb)
