insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000005', 12, 'A2', 'Salud, cuerpo y consejos', 'Aprende a decir qué te duele con «wehtun» + dativo (mir, dir, ihm) o con «Ich habe …schmerzen», y a dar consejos con «Du solltest …» + infinitivo al final.', '[{"heading": "«Mir tut der Kopf weh»: quién duele y a quién", "body": "En alemán la parte del cuerpo es el sujeto: ella «hace daño». La persona va en DATIVO: mir, dir, ihm, ihr, uns. Por eso decimos «Mir tut der Kopf weh», nunca «Ich tue weh» para decir que a ti te duele algo. Si duelen varias partes, el verbo va en plural: «tun».", "bullets": ["Persona en dativo: mir, dir, ihm, ihr, uns.", "Una parte: tut. Varias partes: tun.", "«Mir tut der Rücken weh» = me duele la espalda."]}, {"heading": "Dos formas igual de correctas", "body": "Además de «wehtun» tienes «Ich habe Kopfschmerzen». Las dos son correctas y muy usadas: elige la que quieras. Con «haben» juntas la parte del cuerpo y «-schmerzen» en una palabra: Kopfschmerzen, Bauchschmerzen, Halsschmerzen, Rückenschmerzen.", "bullets": ["Mir tut der Bauch weh. = Ich habe Bauchschmerzen.", "Con haben: Kopf + schmerzen → Kopfschmerzen.", "También: Ich habe Fieber. Ich bin krank."]}, {"heading": "Aconsejar: «Du solltest …» + infinitivo al final", "body": "«Solltest» viene de «sollen» y sirve para dar consejos suaves: deberías. El verbo principal queda en infinitivo y va SIEMPRE al final de la frase, detrás de todo lo demás.", "bullets": ["Du solltest heute zu Hause bleiben.", "El infinitivo cierra la frase: gehen, trinken, schlafen.", "Formas: ich sollte, du solltest, er sollte."]}]'::jsonb, '[{"de": "Mir tut der Kopf weh.", "es": "Me duele la cabeza.", "text": "Mir tut der Kopf weh.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8c36b75b-670c-5201-84a8-fc2745ceeac2.mp3"}, {"de": "Mir tun die Füße weh.", "es": "Me duelen los pies.", "text": "Mir tun die Füße weh.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/89e2fe02-493d-5198-8a9d-24bea56289a4.mp3"}, {"de": "Ich habe Halsschmerzen und Fieber.", "es": "Tengo dolor de garganta y fiebre.", "text": "Ich habe Halsschmerzen und Fieber.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6bc9f047-719b-5699-b710-6353b9c2a636.mp3"}, {"de": "Du solltest heute zum Arzt gehen.", "es": "Deberías ir hoy al médico.", "text": "Du solltest heute zum Arzt gehen.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1b405eba-a17a-521f-8bfa-8cca0aec82fb.mp3"}]'::jsonb, '[{"title": "«Ich tue weh» no existe con este sentido", "body": "El español dice «yo me duelo», pero en alemán quien duele es la parte del cuerpo. Di «Mir tut der Kopf weh», no «Ich tue weh»."}, {"title": "mir, no mich", "body": "Con wehtun la persona va en dativo (mir, dir, ihm), no en acusativo. «Mich tut der Bauch weh» está mal; lo correcto es «Mir tut der Bauch weh»."}, {"title": "Si duelen varias partes, «tun»", "body": "El sujeto es la parte del cuerpo, así que el verbo concuerda con ella: «Mir tun die Füße weh» (plural), no «Mir tut die Füße weh». Con una sola parte, «tut»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «me duele la barriga»?", "options": ["Mir tut der Bauch weh.", "Ich tue den Bauch weh.", "Mich tut der Bauch weh."], "answer": "Mir tut der Bauch weh.", "id": "u12q1"}, {"type": "multiple_choice", "prompt": "Consejo: «Deberías quedarte hoy en casa». ¿Qué frase tiene el orden correcto?", "options": ["Du solltest heute zu Hause bleiben.", "Du solltest bleiben heute zu Hause.", "Du bleiben solltest heute zu Hause."], "answer": "Du solltest heute zu Hause bleiben.", "id": "u12q2"}, {"type": "cloze", "prompt": "Escribe el pronombre en dativo para YO: «me duele la cabeza».", "text": "___ tut der Kopf weh.", "answer": "Mir", "accepted": ["mir"], "id": "u12q3"}, {"type": "cloze", "prompt": "Duelen los DOS pies: escribe el verbo en la forma correcta (tut / tun).", "text": "Mir ___ die Füße weh.", "answer": "tun", "accepted": ["tun"], "id": "u12q4"}, {"type": "cloze", "prompt": "Consejo: escribe el infinitivo de «quedarse» que cierra la frase.", "text": "Du solltest heute im Bett ___.", "answer": "bleiben", "accepted": ["bleiben"], "id": "u12q5"}]'::jsonb)
